@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@if (IsDot && Pulse)
{
    <span class="relative inline-flex h-2 w-2" @attributes="AdditionalAttributes">
        <span class="animate-ping absolute inline-flex h-full w-full rounded-[calc(var(--radius)*2)] opacity-75 @PulseColorClass"></span>
        <span class="relative inline-flex rounded-[calc(var(--radius)*2)] h-2 w-2 @DotClasses @Class"></span>
    </span>
}
else if (IsDot)
{
    <div class="@CssClass" @attributes="AdditionalAttributes"></div>
}
else
{
    <div class="@CssClass" @attributes="AdditionalAttributes">
        @if (IconContent != null)
        {
            <span class="me-1 inline-flex items-center">@IconContent</span>
        }
        @ChildContent
        @if (IsRemovable)
        {
            <button type="button" class="ms-1 rounded-[calc(var(--radius)*2)] hover:bg-foreground/20 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1" @onclick="HandleRemove" aria-label="@L["Badge.Remove"]">
                <SvgGlyph Svg="@(LumeoIcons.X)" class="h-3 w-3" />
            </button>
        }
    </div>
}

@code {
    /// <summary>The badge's content. Ignored when <see cref="IsDot"/> is true.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>Icon slot. Named <c>IconContent</c> to avoid shadowing the <c>&lt;Icon&gt;</c> component.</summary>
    [Parameter] public RenderFragment? IconContent { get; set; }

    /// <summary>Color variant. <see cref="BadgeVariant.Default"/> (primary) is applied when unset.</summary>
    [Parameter] public BadgeVariant Variant { get; set; } = BadgeVariant.Default;
    /// <summary>Badge size — drives text size + padding. <c>Md</c> (default)
    /// reproduces the historical badge metrics. Use <c>Sm</c> for dense
    /// inline tags / counts and <c>Lg</c> for prominent status chips — avoids
    /// consumer-side <c>!px-*</c> / <c>!h-*</c> / <c>!text-*</c> overrides.</summary>
    [Parameter] public BadgeSize Size { get; set; } = BadgeSize.Md;
    /// <summary>Pill shape instead of the default <c>rounded-md</c> — for count/quota
    /// chips. Theme-radius-aware: renders as a full pill at stock radii and squares off
    /// along with the rest of the UI in sharp themes (<c>--radius: 0</c>).</summary>
    [Parameter] public bool Pill { get; set; }
    /// <summary>Renders the badge as a small filled dot instead of a chip with text — for
    /// status indicators. When set, <see cref="ChildContent"/>/<see cref="IconContent"/>/
    /// <see cref="IsRemovable"/> are not rendered.</summary>
    [Parameter] public bool IsDot { get; set; }
    /// <summary>Adds a pulsing ping ring around a dot badge. Only has an effect when
    /// <see cref="IsDot"/> is also true.</summary>
    [Parameter] public bool Pulse { get; set; }
    /// <summary>Renders a trailing remove (×) button that raises <see cref="OnRemove"/> when clicked.</summary>
    [Parameter] public bool IsRemovable { get; set; }
    /// <summary>Invoked when the remove button is clicked. Only rendered when <see cref="IsRemovable"/> is true.</summary>
    [Parameter] public EventCallback OnRemove { get; set; }

    /// <summary>
    /// When true, the badge plays a one-shot pop-in entrance animation
    /// (scale + opacity) on mount. Default is <c>false</c>.
    /// </summary>
    [Parameter] public bool Animated { get; set; }

    /// <summary>Per-badge density override. When null, inherits from any
    /// ancestor <see cref="DensityScope"/>; if neither is set, matches the
    /// historical <c>Comfortable</c> default. Adjusts padding (Spacious also
    /// adds a touch of vertical padding); text size + radius are unchanged.
    /// Has no effect on dot badges.</summary>
    [Parameter] public Density? Density { get; set; }
    [CascadingParameter] private Density? InheritedDensity { get; set; }
    /// <summary>Additional CSS classes merged onto the badge's root element.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Additional HTML attributes captured and forwarded to the badge's root element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private Lumeo.Density EffectiveDensity => Density ?? InheritedDensity ?? Lumeo.Density.Comfortable;

    private string CssClass
    {
        get
        {
            var animatedClass = Animated ? "lumeo-badge-animated" : null;
            var shape = Pill ? "rounded-[calc(var(--radius)*2)]" : "rounded-md";
            return IsDot
                ? Cx.Merge("inline-flex h-2 w-2 rounded-[calc(var(--radius)*2)] p-0", VariantClasses, animatedClass, Class)
                : Cx.Merge(BaseClasses, shape, TextClass, PadClass, VariantClasses, animatedClass, Class);
        }
    }

    private string TextClass => Size switch
    {
        BadgeSize.Sm => "text-[10px]",
        BadgeSize.Lg => "text-sm",
        _ => "text-xs"
    };

    // Padding tracks Size first, then Density nudges within the size.
    // (Md, Comfortable) reproduces the historical px-2.5 py-0.5.
    private string PadClass => (Size, EffectiveDensity) switch
    {
        (BadgeSize.Sm, Lumeo.Density.Compact)  => "px-1.5 py-0",
        (BadgeSize.Sm, Lumeo.Density.Spacious) => "px-2.5 py-0.5",
        (BadgeSize.Sm, _)                      => "px-2 py-0",
        (BadgeSize.Lg, Lumeo.Density.Compact)  => "px-2.5 py-0.5",
        (BadgeSize.Lg, Lumeo.Density.Spacious) => "px-4 py-1.5",
        (BadgeSize.Lg, _)                      => "px-3 py-1",
        (_, Lumeo.Density.Compact)             => "px-2 py-0.5",
        (_, Lumeo.Density.Spacious)            => "px-3 py-1",
        _                                      => "px-2.5 py-0.5"
    };

    private const string BaseClasses = "inline-flex items-center border font-semibold transition-colors focus:outline-none";

    private string DotClasses => VariantClasses;

    private string PulseColorClass => Variant switch
    {
        BadgeVariant.Default => "bg-primary",
        BadgeVariant.Secondary => "bg-secondary",
        BadgeVariant.Destructive => "bg-destructive",
        BadgeVariant.Outline => "bg-foreground",
        BadgeVariant.Success => "bg-success-text",
        BadgeVariant.Warning => "bg-warning-text",
        _ => "bg-primary"
    };

    private string VariantClasses => Variant switch
    {
        BadgeVariant.Default => "border-transparent bg-primary text-primary-foreground shadow",
        BadgeVariant.Secondary => "border-transparent bg-secondary text-secondary-foreground",
        BadgeVariant.Destructive => "border-transparent bg-destructive text-destructive-foreground shadow",
        BadgeVariant.Outline => "border-border/60 text-foreground",
        BadgeVariant.Success => "border-transparent bg-success-light text-success-text",
        BadgeVariant.Warning => "border-transparent bg-warning-light text-warning-text",
        _ => ""
    };

    // Visibility is driven by data, not internal latch state: HandleRemove
    // notifies the consumer, who removes the item from their model. This avoids
    // a stale _isRemoved latch hiding the wrong badge when an instance is reused
    // (e.g. an unkeyed list that recycles this component for different content).
    private Task HandleRemove() => OnRemove.InvokeAsync();

    public enum BadgeVariant { Default, Secondary, Destructive, Outline, Success, Warning }
    public enum BadgeSize { Sm, Md, Lg }
}
